INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (27, "人助けが大好き！　前向き格闘娘", "トゥインクルウィッシュ", "ヒヨリ", 155, 100101, "人助け、応援", "東山奈央", "A", 2, 8, 16, 44, "獣人族", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (5, "戦闘のサポートが得意な、心優しい少女", "トゥインクルウィッシュ", "ユイ", 158, 100201, "料理、人間観察", "種田梨沙", "O", 2, 4, 17, 47, "ヒューマン", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (12, "クールで何事にも真っ直ぐな剣士", "トゥインクルウィッシュ", "レイ", 163, 100301, "読書、乗馬、お茶", "早見沙織", "B", 2, 1, 18, 46, "魔族", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (10, "探検好きのイタズラっ子", "リトルリリカル", "ミソギ", 128, 100401, "いたずら、探検", "諸星すみれ", "O", 5, 8, 9, 27, "ヒューマン", "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (25, "ヒーローに憧れる騎士見習いの少女", "王宮騎士団（NIGHTMARE）", "マツリ", 146, 100501, "ヒーローごっこ", "下田麻美", "O", 8, 11, 12, 40, "獣人族", "？？？", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (22, "甘え上手なみんなの人気者", "悪魔偽王国軍（ディアボロス）", "アカリ", 150, 100601, "サックス", "浅倉杏美", "O", 7, 11, 13, 42, "魔族", "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (23, "プリン大好きゴースト娘", "悪魔偽王国軍（ディアボロス）", "ミヤコ", 130, 100701, "プリンを食べること", "雨宮天", "B", 7, 1, 14, 32, "魔族", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (10, "ボクは誰よりも美しい", "ヴァイスフリューゲル　ランドソル支部", "ユキ", 150, 100801, "鏡で自分を見ること", "大空直美", "AB", 15, 10, 14, 40, "エルフ", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (5, "前世を信じる中二病患者、「疾風の冥姫」", "トワイライトキャラバン", "アンナ", 159, 100901, "小説執筆", "髙野麻美", "A", 13, 7, 17, 45, "魔族", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (22, "マホマホ王国のプリンセス", "自警団（カォン）", "マホ", 155, 101001, "空想、ぬいぐるみ集め", "内田真礼", "O", 10, 9, 16, 42, "獣人族", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (25, "人懐っこくてマシンガントークな妹系少女", "ラビリンス", "リノ", 156, 101101, "お裁縫", "阿澄佳奈", "A", 3, 8, 15, 44, "ヒューマン", "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (24, "みんなのために超能力を使う眠り姫", "フォレスティエ", "ハツネ", 156, 101201, "妹と遊ぶこと、二度寝、昼寝、早寝", "大橋彩香", "A", 6, 12, 17, 46, "エルフ", "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (21, "オタク全開な魔法少女", "トワイライトキャラバン", "ナナカ", 166, 101301, "読書、魔法", "佳村はるか", "O", 13, 8, 18, 55, "魔族", "", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (3, "頭脳明晰な美少女名探偵", "自警団（カォン）", "カスミ", 152, 101401, "読書、推理", "水瀬いのり", "AB", 10, 11, 15, 41, "獣人族", "test", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (5, "母性溢れる優しいみんなの「ミサト先生」", "フォレスティエ", "ミサト", 165, 101501, "絵本作り", "國府田マリ子", "O", 6, 9, 21, 54, "エルフ", "test", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (10, "天真爛漫で人気者のカリスマモデル", "ルーセント学院", "スズナ", 167, 101601, "ファッション", "上坂すみれ", "O", 14, 4, 17, 48, "魔族", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (7, "いつでも「なんくるないさ～」な天然娘", "自警団（カォン）", "カオリ", 158, 101701, "踊り、空手", "高森奈津美", "A", 10, 7, 17, 53, "獣人族", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (14, "多くの男性を魅了する無垢な女教師", "ルーセント学院", "イオ", 162, 101801, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "伊藤静", "B", 14, 8, 23, 52, "魔族", "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (3, "お歌もにんじんも、ウサギさんも大好き♪", "リトルリリカル", "ミミ", 117, 102001, "かわいいもの集め", "日高里菜", "O", 5, 4, 10, 21, "獣人族", "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (9, "泣き虫で臆病な守ってあげたい女の子", "サレンディア救護院", "クルミ", 150, 102101, "観劇、おままごと", "植田佳奈", "B", 9, 6, 12, 40, "ヒューマン", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (22, "人見知りであまのじゃくな女の子", "悪魔偽王国軍（ディアボロス）", "ヨリ", 150, 102201, "ゲーム全般", "原紗友里", "O", 7, 11, 13, 40, "魔族", "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (10, "ぷうきちといつも一緒！", "サレンディア救護院", "アヤネ", 148, 102301, "屋内でできる遊び", "芹澤優", "B", 9, 5, 14, 38, "ヒューマン", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (12, "お嬢さまのためにがんばるドジっ娘メイド", "サレンディア救護院", "スズメ", 154, 102501, "ご奉仕", "悠木碧", "O", 9, 12, 15, 43, "ヒューマン", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (1, "遊びと睡眠が何より大事なぐうたら娘", "牧場（エリザベスパーク）", "リン", 144, 102601, "あんパン", "小岩井ことり", "B", 11, 1, 17, 42, "獣人族", "test", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (30, "運命の相手に一途すぎる乙女", "トワイライトキャラバン", "エリコ", 154, 102701, "実験、裁縫、料理", "橋本ちなみ", "B", 13, 7, 16, 43, "魔族", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (4, "救護院を経営する優しい庶民派お嬢様", "サレンディア救護院", "サレン", 156, 102801, "経営、お茶会", "堀江由衣", "A", 9, 10, 17, 43, "エルフ", "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (24, "歌って踊れる大人気アイドル", "カルミナ", "ノゾミ", 157, 102901, "舞台鑑賞、ダンス", "日笠陽子", "B", 4, 1, 17, 40, "ヒューマン", "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (31, "トーゴクの神秘、オシエテクダサイ！", "ヴァイスフリューゲル　ランドソル支部", "ニノン", 163, 103001, "忍法開発", "佐藤聡美", "O", 15, 8, 16, 51, "ヒューマン", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (22, "占いが得意な霊能少女", "悪魔偽王国軍（ディアボロス）", "シノブ", 157, 103101, "占い", "大坪由佳", "AB", 7, 12, 18, 42, "魔族", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (12, "一人前の商人を目指すパワフルお嬢様", "メルクリウス財団", "アキノ", 157, 103201, "慈善事業", "松嵜麗", "AB", 12, 3, 18, 45, "ヒューマン", "この私とともにいる限り、\nお金に不自由はさせませんわ！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (3, "みんなを笑顔にするお笑い牧場主", "牧場（エリザベスパーク）", "マヒル", 142, 103301, "漫才", "新田恵海", "B", 11, 3, 20, 35, "ヒューマン", "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (16, "純情でほっとけない大人の女性", "メルクリウス財団", "ユカリ", 164, 103401, "ウインドーショッピング", "今井麻美", "A", 12, 3, 22, 55, "エルフ", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (2, "礼儀正しくしっかり者のちびっ子優等生", "リトルリリカル", "キョウカ", 118, 103601, "お勉強", "小倉唯", "A", 5, 2, 8, 21, "エルフ", "test", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (11, "義理堅くてからかい好きな剣術少女", "王宮騎士団（NIGHTMARE）", "トモ", 149, 103701, "剣術、年長者をからかう", "茅原実里", "A", 8, 8, 13, 43, "ヒューマン", "test", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (3, "読書が趣味の病弱少女", "牧場（エリザベスパーク）", "シオリ", 153, 103801, "読書、お散歩", "小清水亜美", "A", 11, 11, 14, 40, "獣人族", "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (6, "「友達」に憧れる、エルフの森の女の子", "フォレスティエ", "アオイ", 158, 104001, "友達作りのイメトレ", "花澤香菜", "AB", 6, 6, 13, 44, "エルフ", "友達ができるその日まで…\nBB団で\nトレーニングですっ！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (3, "人々を守るために歌う、唱喚士の少女", "カルミナ", "チカ", 163, 104201, "各種楽器", "福原綾香", "O", 4, 6, 17, 46, "ヒューマン", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (9, "男勝りで情に厚いワイルド娘", "自警団（カォン）", "マコト", 168, 104301, "お菓子作り", "小松未可子", "O", 10, 8, 17, 54, "獣人族", "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (5, "かつては夜を支配した最強の吸血鬼", "悪魔偽王国軍（ディアボロス）", "イリヤ", 172, 104401, "世界征服", "丹下桜", "A", 7, 5, "??", 50, "魔族", "test", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (19, "妄想大好き！　ほんとは照れ屋な女の子", "ヴァイスフリューゲル　ランドソル支部", "クウカ", 157, 104501, "小説を読むこと", "長妻樹里", "AB", 15, 11, 18, 49, "ヒューマン", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (1, "弱きを助け強きをくじく猫娘", "メルクリウス財団", "タマキ", 158, 104601, "猫とたわむれること", "沼倉愛美", "AB", 12, 3, 19, 48, "獣人族", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (25, "素顔を見せない冷静沈着な女性騎士", "王宮騎士団（NIGHTMARE）", "ジュン", 171, 104701, "格闘技、湯浴み", "川澄綾子", "A", 8, 10, 25, 50, "ヒューマン", "？？？", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (11, "仕事も私事も効率優先な傭兵少女", "メルクリウス財団", "ミフユ", 163, 104801, "傭兵などのアルバイト", "田所あずさ", "O", 12, 11, 20, 49, "ヒューマン", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (24, "お姉ちゃんがお世話してあげるからねっ！", "ラビリンス", "シズル", 168, 104901, "家事全般", "生天目仁美", "O", 3, 10, 18, 54, "ヒューマン", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (3, "ちょっとおませな恋に恋する女の子", "ルーセント学院", "ミサキ", 120, 105001, "ファッション誌鑑賞、コスメ集め", "久野美咲", "A", 14, 1, 11, 22, "魔族", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (7, "実験が趣味の危険な科学者", "トワイライトキャラバン", "ミツキ", 166, 105101, "研究、実験", "三石琴乃", "A", 13, 3, 27, 53, "ヒューマン", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (14, "乙女チックなもふもふアニマル", "牧場（エリザベスパーク）", "リマ", 150, 105201, "毛繕い、お喋り", "徳井青空", "A", 11, 3, 17, 100, "獣人族", "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (28, "見た目も中身もお子ちゃまな異国の軍人", "ヴァイスフリューゲル　ランドソル支部", "モニカ", 140, 105301, "お菓子屋通い", "辻あゆみ", "A", 15, 7, 17, 33, "ヒューマン", "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (7, "ファッション大好きなキュートガール", "カルミナ", "ツムギ", 153, 105401, "裁縫", "木戸衣吹", "AB", 4, 9, 14, 45, "ヒューマン", "test", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (7, "どこまでも一途に慕う、純情乙女", "ヴァイスフリューゲル　ランドソル支部", "アユミ", 155, 105501, "観察", "大関英里", "O", 15, 4, 16, 43, "エルフ", "test", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (11, "人情味溢れる粋でいなせな「姉御」", "トワイライトキャラバン", "ルカ", 167, 105601, "釣り", "佐藤利奈", "B", 13, 7, 25, 54, "ヒューマン", "test", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (10, "空への冒険を夢見る騎空士の少女", "？？？", "ジータ", 156, 105701, "冒険、おしゃべり", "金元寿子", "O", "", 3, 17, 45, "ヒューマン", "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (31, "いつも元気な腹ペコ少女", "美食殿", "ペコリーヌ", 156, 105801, "食べ歩き、料理", "M・A・O", "O", 1, 3, 17, 46, "ヒューマン", "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (11, "主を慕う、小さなガイド役", "美食殿", "コッコロ", 140, 105901, "瞑想、動植物の飼育", "伊藤美来", "B", 1, 5, 11, 35, "エルフ", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (2, "行き倒れの謎のネコミミ魔法使い", "美食殿", "キャル", 152, 106001, "猫と遊ぶ", "立花理香", "A", 1, 9, 14, 39, "獣人族", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (11, "さまよえる謎の少女", "？？？", "ムイミ", 148, 106101, "冒険、思い出話", "潘めぐみ", "O", "", 8, 16, 40, "ヒューマン", "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", 0);
