INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (31, "いつも元気な腹ペコ少女", "美食殿", "ペコリーヌ（サマー）", 156, 107501, "食べ歩き、料理", "M・A・O", "O", 1, 3, 17, 46, "ヒューマン", "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (11, "主を慕う、小さなガイド役", "美食殿", "コッコロ（サマー）", 140, 107601, "瞑想、動植物の飼育", "伊藤美来", "B", 1, 5, 11, 35, "エルフ", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (12, "お嬢さまのためにがんばるドジっ娘メイド", "サレンディア救護院", "スズメ（サマー）", 154, 107701, "ご奉仕", "悠木碧", "O", 9, 12, 15, 43, "ヒューマン", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (2, "行き倒れの謎のネコミミ魔法使い", "美食殿", "キャル（サマー）", 152, 107801, "猫と遊ぶ", "立花理香", "A", 1, 9, 14, 39, "獣人族", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (1, "弱きを助け強きをくじく猫娘", "メルクリウス財団", "タマキ（サマー）", 158, 107901, "猫とたわむれること", "沼倉愛美", "AB", 12, 3, 19, 48, "獣人族", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (11, "仕事も私事も効率優先な傭兵少女", "メルクリウス財団", "ミフユ（サマー）", 163, 108001, "傭兵などのアルバイト", "田所あずさ", "O", 12, 11, 20, 49, "ヒューマン", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (22, "占いが得意な霊能少女", "悪魔偽王国軍（ディアボロス）", "シノブ（ハロウィン）", 157, 108101, "占い", "大坪由佳", "AB", 7, 12, 18, 42, "魔族", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (23, "プリン大好きゴースト娘", "悪魔偽王国軍（ディアボロス）", "ミヤコ（ハロウィン）", 130, 108201, "プリンを食べること", "雨宮天", "B", 7, 1, 14, 32, "魔族", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (3, "ちょっとおませな恋に恋する女の子", "ルーセント学院", "ミサキ（ハロウィン）", 120, 108301, "ファッション誌鑑賞、コスメ集め", "久野美咲", "A", 14, 1, 11, 22, "魔族", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (3, "人々を守るために歌う、唱喚士の少女", "カルミナ", "チカ（クリスマス）", 163, 108401, "各種楽器", "福原綾香", "O", 4, 6, 17, 46, "ヒューマン", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (9, "泣き虫で臆病な守ってあげたい女の子", "サレンディア救護院", "クルミ（クリスマス）", 150, 108501, "観劇、おままごと", "植田佳奈", "B", 9, 6, 12, 40, "ヒューマン", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (10, "ぷうきちといつも一緒！", "サレンディア救護院", "アヤネ（クリスマス）", 148, 108601, "屋内でできる遊び", "芹澤優", "B", 9, 5, 14, 38, "ヒューマン", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (27, "人助けが大好き！　前向き格闘娘", "トゥインクルウィッシュ", "ヒヨリ（ニューイヤー）", 155, 108701, "人助け、応援", "東山奈央", "A", 2, 8, 16, 44, "獣人族", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (5, "戦闘のサポートが得意な、心優しい少女", "トゥインクルウィッシュ", "ユイ（ニューイヤー）", 158, 108801, "料理、人間観察", "種田梨沙", "O", 2, 4, 17, 47, "ヒューマン", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (12, "クールで何事にも真っ直ぐな剣士", "トゥインクルウィッシュ", "レイ（ニューイヤー）", 163, 108901, "読書、乗馬、お茶", "早見沙織", "B", 2, 1, 18, 46, "魔族", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (30, "運命の相手に一途すぎる乙女", "トワイライトキャラバン", "エリコ（バレンタイン）", 154, 109001, "実験、裁縫、料理", "橋本ちなみ", "B", 13, 7, 16, 43, "魔族", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (24, "お姉ちゃんがお世話してあげるからねっ！", "ラビリンス", "シズル（バレンタイン）", 168, 109101, "家事全般", "生天目仁美", "O", 3, 10, 18, 54, "ヒューマン", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (1, "英霊と契約を結んだマナリアの天才王女", "？？？", "アン", 156, 109201, "読書", "日笠陽子", "AB", "", 12, 17, 55, "ヒューマン", "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (4, "マナリア魔法学院の新入生", "？？？", "ルゥ", 144, 109301, "食べること、眠ること", "こやまきみこ", "O", "", 2, 16, 45, "ヒューマン", "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (3, "人を超越した力を有す心優しい竜姫", "？？？", "グレア", 167, 109401, "ピアノ", "福原綾香", "B", "", 11, 17, 67, "半人半竜", "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (19, "妄想大好き！　ほんとは照れ屋な女の子", "ヴァイスフリューゲル　ランドソル支部", "クウカ（オーエド）", 157, 109501, "小説を読むこと", "長妻樹里", "AB", 15, 11, 18, 49, "ヒューマン", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (31, "トーゴクの神秘、オシエテクダサイ！", "ヴァイスフリューゲル　ランドソル支部", "ニノン（オーエド）", 163, 109601, "忍法開発", "佐藤聡美", "O", 15, 8, 16, 51, "ヒューマン", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (2, "鬼がかりの万能妹メイド", "？？？", "レム", 154, 109701, "演劇鑑賞、詩文", "水瀬いのり", "?", "", 2, 17, "??", "鬼族", "", 0);
