INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (21, "オタク全開な魔法少女", "トワイライトキャラバン", "ナナカ（サマー）", 166, 113301, "読書、魔法", "佳村はるか", "O", 13, 8, 18, 55, "魔族", "", 0);
