INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (4, "救護院を経営する優しい庶民派お嬢様", "サレンディア救護院", "サレン（クリスマス）", 156, 114501, "経営、お茶会", "堀江由衣", "A", 9, 10, 17, 43, "エルフ", "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (16, "純情でほっとけない大人の女性", "メルクリウス財団", "ユカリ（クリスマス）", 164, 114601, "ウインドーショッピング", "今井麻美", "A", 12, 3, 22, 55, "エルフ", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (11, "さまよえる謎の少女", "？？？", "ムイミ（ニューイヤー）", 148, 114701, "冒険、思い出話", "潘めぐみ", "O", "", 8, 16, 40, "ヒューマン", "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", 0);
