INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (11, "主を慕う、小さなガイド役", "美食殿", "コッコロ（儀装束）", 140, 115501, "瞑想、動植物の飼育", "伊藤美来", "B", 1, 5, 11, 35, "エルフ", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (5, "戦闘のサポートが得意な、心優しい少女", "トゥインクルウィッシュ", "ユイ（儀装束）", 158, 115601, "料理、人間観察", "種田梨沙", "O", 2, 4, 17, 47, "ヒューマン", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (3, "頭脳明晰な美少女名探偵", "自警団（カォン）", "カスミ（サマー）", 152, 115701, "読書、推理", "水瀬いのり", "AB", 10, 11, 15, 41, "獣人族", "", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (14, "乙女チックなもふもふアニマル", "牧場（エリザベスパーク）", "リマ（シンデレラ）", 150, 115801, "毛繕い、お喋り", "徳井青空", "A", 11, 3, 17, 100, "獣人族", "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (9, "男勝りで情に厚いワイルド娘", "自警団（カォン）", "マコト（シンデレラ）", 168, 115901, "お菓子作り", "小松未可子", "O", 10, 8, 17, 54, "獣人族", "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (22, "マホマホ王国のプリンセス", "自警団（カォン）", "マホ（シンデレラ）", 155, 116001, "空想、ぬいぐるみ集め", "内田真礼", "O", 10, 9, 16, 42, "獣人族", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 0);
