INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (1, "弱きを助け強きをくじく猫娘", "メルクリウス財団", "タマキ（作業服）", 158, 116801, "猫とたわむれること", "沼倉愛美", "AB", 12, 3, 19, 48, "獣人族", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (11, "仕事も私事も効率優先な傭兵少女", "メルクリウス財団", "ミフユ（作業服）", 163, 116901, "傭兵などのアルバイト", "田所あずさ", "O", 12, 11, 20, 49, "ヒューマン", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (30, "運命の相手に一途すぎる乙女", "トワイライトキャラバン", "エリコ（サマー）", 154, 117001, "実験、裁縫、料理", "橋本ちなみ", "B", 13, 7, 16, 43, "魔族", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (24, "お姉ちゃんがお世話してあげるからねっ！", "ラビリンス", "シズル（サマー）", 168, 117101, "家事全般", "生天目仁美", "O", 3, 10, 18, 54, "ヒューマン", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (24, "歌って踊れる大人気アイドル", "カルミナ", "ノゾミ（サマー）", 157, 117201, "舞台鑑賞、ダンス", "日笠陽子", "B", 4, 1, 17, 40, "ヒューマン", "", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (3, "人々を守るために歌う、唱喚士の少女", "カルミナ", "チカ（サマー）", 163, 117301, "各種楽器", "福原綾香", "O", 4, 6, 17, 46, "ヒューマン", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (7, "ファッション大好きなキュートガール", "カルミナ", "ツムギ（サマー）", 153, 117401, "裁縫", "木戸衣吹", "AB", 4, 9, 14, 45, "ヒューマン", "", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (7, "実験が趣味の危険な科学者", "トワイライトキャラバン", "ミツキ（オーエド）", 166, 117501, "研究、実験", "三石琴乃", "A", 13, 3, 27, 53, "ヒューマン", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (10, "ボクは誰よりも美しい", "ヴァイスフリューゲル　ランドソル支部", "ユキ（オーエド）", 150, 117601, "鏡で自分を見ること", "大空直美", "AB", 15, 10, 14, 40, "エルフ", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (7, "いつでも「なんくるないさ～」な天然娘", "自警団（カォン）", "カオリ（ハロウィン）", 158, 117701, "踊り、空手", "高森奈津美", "A", 10, 7, 17, 53, "獣人族", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (31, "トーゴクの神秘、オシエテクダサイ！", "ヴァイスフリューゲル　ランドソル支部", "ニノン（ハロウィン）", 163, 117801, "忍法開発", "佐藤聡美", "O", 15, 8, 16, 51, "ヒューマン", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (10, "天真爛漫で人気者のカリスマモデル", "ルーセント学院", "スズナ（ハロウィン）", 167, 117901, "ファッション", "上坂すみれ", "O", 14, 4, 17, 48, "魔族", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 0);
