INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (14, "多くの男性を魅了する無垢な女教師", "ルーセント学院", "イオ（ノワール）", 162, 119001, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "伊藤静", "B", 14, 8, 23, 52, "魔族", "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (19, "妄想大好き！　ほんとは照れ屋な女の子", "ヴァイスフリューゲル　ランドソル支部", "クウカ（ノワール）", 157, 119101, "小説を読むこと", "長妻樹里", "AB", 15, 11, 18, 49, "ヒューマン", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 0);
