INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (5, "前世を信じる中二病患者、「疾風の冥姫」", "トワイライトキャラバン", "アンナ（パイレーツ）", 159, 121901, "小説執筆", "髙野麻美", "A", 13, 7, 17, 45, "魔族", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (22, "占いが得意な霊能少女", "悪魔偽王国軍（ディアボロス）", "シノブ（パイレーツ）", 157, 122001, "占い", "大坪由佳", "AB", 7, 12, 18, 42, "魔族", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (6, "「友達」に憧れる、エルフの森の女の子", "フォレスティエ", "アオイ（キャンプ）", 158, 122101, "友達作りのイメトレ", "花澤香菜", "AB", 6, 6, 13, 44, "エルフ", "", 0);
