INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (6, "けんぞくのご主人様", "？？？", "ヴァンピィ", 149, 122301, "お散歩、お料理", "釘宮理恵", "AB", "", 12, "??", 41, "魔族", "", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (27, "人助けが大好き！　前向き格闘娘", "トゥインクルウィッシュ", "ヒヨリ（サマー）", 155, 122401, "人助け、応援", "東山奈央", "A", 2, 8, 16, 44, "獣人族", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (12, "クールで何事にも真っ直ぐな剣士", "トゥインクルウィッシュ", "レイ（サマー）", 163, 122501, "読書、乗馬、お茶", "早見沙織", "B", 2, 1, 18, 46, "魔族", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (5, "戦闘のサポートが得意な、心優しい少女", "トゥインクルウィッシュ", "ユイ（サマー）", 158, 122601, "料理、人間観察", "種田梨沙", "O", 2, 4, 17, 47, "ヒューマン", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 0);
