INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (1, "弱きを助け強きをくじく猫娘", "メルクリウス財団", "タマキ（カフェ）", 158, 125101, "猫とたわむれること", "沼倉愛美", "AB", 12, 3, 19, 48, "獣人族", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (28, "見た目も中身もお子ちゃまな異国の軍人", "ヴァイスフリューゲル　ランドソル支部", "モニカ（カフェ）", 140, 125201, "お菓子屋通い", "辻あゆみ", "A", 15, 7, 17, 33, "ヒューマン", "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (11, "主を慕う、小さなガイド役", "美食殿", "コッコロ（レンジャー）", 140, 125301, "瞑想、動植物の飼育", "伊藤美来", "B", 1, 5, 11, 35, "エルフ", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 0);
