INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (2, "行き倒れの謎のネコミミ魔法使い", "美食殿", "キャル（編入生）", 152, 127201, "猫と遊ぶ", "立花理香", "A", 1, 9, 14, 39, "獣人族", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 0);
