INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (5, "戦闘のサポートが得意な、心優しい少女", "トゥインクルウィッシュ", "ユイ（クリスマス）", 158, 136401, "料理、人間観察", "種田梨沙", "O", 2, 4, 17, 47, "ヒューマン", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (24, "お姉ちゃんがお世話してあげるからねっ！", "ラビリンス", "シズル（ニューイヤー）", 168, 136501, "家事全般", "生天目仁美", "O", 3, 10, 18, 54, "ヒューマン", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (8, "がんばりましゅ！　うじゅうじゅタコ娘", "？？？", "ルルィ", 148, 136901, "タコ料理、潮干狩り、ひとりじゃんけん", "飯田ヒカル", "青", "", 10, "13(?)", "??", "？？？", "", 0);
