INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (27, "人助けが大好き！　前向き格闘娘", "トゥインクルウィッシュ", "ヒヨリ（プリンセス）", 155, 180101, "人助け、応援", "東山奈央", "A", 2, 8, 16, 44, "獣人族", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (5, "戦闘のサポートが得意な、心優しい少女", "トゥインクルウィッシュ", "ユイ（プリンセス）", 158, 180201, "料理、人間観察", "種田梨沙", "O", 2, 4, 17, 47, "ヒューマン", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (12, "クールで何事にも真っ直ぐな剣士", "トゥインクルウィッシュ", "レイ（プリンセス）", 163, 180301, "読書、乗馬、お茶", "早見沙織", "B", 2, 1, 18, 46, "魔族", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (31, "いつも元気な腹ペコ少女", "美食殿", "ぺコリーヌ（プリンセス）", 156, 180401, "食べ歩き、料理", "M・A・O", "O", 1, 3, 17, 46, "ヒューマン", "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (11, "主を慕う、小さなガイド役", "美食殿", "コッコロ（プリンセス）", 140, 180501, "瞑想、動植物の飼育", "伊藤美来", "B", 1, 5, 11, 35, "エルフ", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 0);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (2, "行き倒れの謎のネコミミ魔法使い", "美食殿", "キャル（プリンセス）", 152, 180601, "猫と遊ぶ", "立花理香", "A", 1, 9, 14, 39, "獣人族", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 0);
